#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long A, B;
        scanf("%ld %ld", &A, &B);
        long diff = A - B;
        char s[16];
        sprintf(s, "%ld", diff);
        int len = strlen(s);
        // find a digit to change
        int pos = -1;
        for (int i = 0; i < len; ++i) {
            if (s[i] != '9') { pos = i; break; }
        }
        if (pos == -1) pos = len - 1; // all 9's
        char orig = s[pos];
        s[pos] = (orig != '9') ? '9' : '8';
        // avoid leading zero (cannot happen with this rule)
        printf("%s\n", s);
    }
    return 0;
}

