#!/usr/bin/env python3
import sys

def next_wrong(diff_str: str) -> str:
    s = list(diff_str)
    for i, ch in enumerate(s):
        if ch != '9':
            s[i] = '9'
            break
    else:
        s[-1] = '8'
    return ''.join(s)

def main():
    data = sys.stdin.read().strip().split('\n')
    T = int(data[0])
    out_lines = []
    for line in data[1:]:
        A, B = map(int, line.split())
        diff = A - B
        out_lines.append(next_wrong(str(diff)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

